 print("Optimized result: %d" % get_result(Params(best_params['a'], best_params['b'], best_params['c'])))

def is_subsequence(str1, str2):
    i = 0
    j = 0

    while(i < len(str1) and j < len(str2)):
        if str1[i] == str2[j]:
            i += 1
        j += 1

    return i == len(str1)

